package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testGetIgnoreSurroundingSpaces_DefaultFalse() {
        CSVFormat format = CSVFormat.DEFAULT;
        assertFalse(format.getIgnoreSurroundingSpaces());
    }

    @Test
    void testGetIgnoreSurroundingSpaces_WithIgnoreSurroundingSpacesTrue() {
        CSVFormat format = CSVFormat.DEFAULT.withIgnoreSurroundingSpaces(true);
        assertTrue(format.getIgnoreSurroundingSpaces());
    }

    @Test
    void testGetIgnoreSurroundingSpaces_WithIgnoreSurroundingSpacesFalse() {
        CSVFormat format = CSVFormat.DEFAULT.withIgnoreSurroundingSpaces(false);
        assertFalse(format.getIgnoreSurroundingSpaces());
    }

    @Test
    void testGetIgnoreSurroundingSpaces_StaticTDF() {
        assertTrue(CSVFormat.TDF.getIgnoreSurroundingSpaces());
    }

    @Test
    void testGetIgnoreSurroundingSpaces_ExcelFormat() {
        // EXCEL does not set ignoreSurroundingSpaces explicitly, so it inherits DEFAULT's false
        assertFalse(CSVFormat.EXCEL.getIgnoreSurroundingSpaces());
    }

    @Test
    void testGetIgnoreSurroundingSpaces_MysqlFormat() {
        assertFalse(CSVFormat.MYSQL.getIgnoreSurroundingSpaces());
    }
}
